                        "docs/CURRENT_STAGE4D_03BF_PAYMENT_ENGINE_CROSS_WINDOW_GENERATION_CONSUMPTION_ROW_MANIFEST_AUDIT.md",
                        family.DocAnchor,
                        window.DocAnchor
                    ])))
            .ToArray();
    }

