                    .Concat(dispatchRow.DocAnchors)
                    .Distinct(StringComparer.Ordinal)
                    .ToArray());
        }

        throw new InvalidOperationException($"Unsupported 4D-03DK non-target/typed residual verifier row: {dispatchRow.AbilityId}.");
