            Assert.Contains("4D-03BC", entry.AggregateScope, StringComparison.Ordinal);
            Assert.Contains("docs/CURRENT_STAGE4D_03BC_PAYMENT_ENGINE_OFFICIAL_MATRIX_ROW_SCHEMA_AUDIT.md", entry.DocAnchors);
