    [Fact]
    public void PaymentEngineSelectedResourceSkillOfficialRuntimeCardRowParityManifestBindsRuntimeRowsAndFocusedMethods()
    {
        Assert.All(SelectedResourceSkillOfficialRuntimeCardRowParityManifest, entry =>
        {
